import copy


def _parse_path(path):
    if path == "":
        return []
    parts = path.split("/")
    if parts and parts[0] == "":
        parts = parts[1:]
    return [p.replace("~1", "/").replace("~0", "~") for p in parts]


def _navigate(doc, tokens):
    current = doc
    for token in tokens:
        if isinstance(current, list):
            current = current[int(token)]
        else:
            current = current[token]
    return current


def apply_patch(document, operations):
    doc = copy.deepcopy(document)
    for operation in operations:
        op = operation["op"]
        tokens = _parse_path(operation["path"])
        if not tokens:
            if op in ("add", "replace"):
                doc = copy.deepcopy(operation.get("value"))
            continue
        parent = _navigate(doc, tokens[:-1])
        last = tokens[-1]
        if op == "add":
            if isinstance(parent, list):
                if last == "-":
                    parent.append(operation.get("value"))
                else:
                    parent.insert(int(last), operation.get("value"))
            else:
                parent[last] = operation.get("value")
        elif op == "replace":
            if isinstance(parent, list):
                parent[int(last)] = operation.get("value")
            else:
                parent[last] = operation.get("value")
        elif op == "remove":
            if isinstance(parent, list):
                del parent[int(last)]
            else:
                del parent[last]
    return doc
